from agent import *from models.products import *def run(context, session):    session.queue(Request("https://memeburn.com/gearburn/category/reviews/"), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath("(//div[@id='content'] | //div[@class='container-fluid py-4 mb-3'])//div[contains(@class, 'postblock ')]")    for rev in revs:        title = rev.xpath(".//h2[@class='entry-title']//a//text()").string(multiple=True)        url = rev.xpath(".//h2[@class='entry-title']//a/@href").string()        cat = rev.xpath(".//span[@class='category']//text()").string(multiple=True)        session.queue(Request(url), process_review, dict(context, url=url, title=title, cat=cat))    next_url = data.xpath("//a[@class='next page-link']/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.url = context["url"]    product.ssid = product.url.split('/')[-2]    product.category = context["cat"]    title = context['title']    if "we review:" in title.lower():        title = title.title().split("We Review: ")[1]    elif "we review " in title.lower():        title = title.title().split("We Review ")[1]    elif "preview: " in title.lower():        title = title.title().split("Preview: ")[0]    elif "review: " in title.lower():        title = title.title().split("Review: ")[0]    elif " buy the " in title:        title = title.title().split(" Buy The ")[1]    elif " review" in title.lower():        title = title.title().split(" Review")[0].split(" Hands-On")[0]    elif " pureview" in title.lower():        title = title.lower().title().split(" Pureview ")[0]    else:        title = title.split(': ')[0]    product.name = title    review = Review()    review.type = "pro"    review.title = context["title"]    review.ssid = product.ssid    review.url = product.url    date = data.xpath("//h1[contains(@class, 'entry-title')]/preceding-sibling::div[@class='entry-meta']//time/@datetime").string()    if date:        review.date = date.split('T')[0]    author = data.xpath("//div[contains(@class, 'single__author-card')]").first()    if author:        name = author.xpath(".//h4//text()").string()        url = author.xpath(".//a/@href").string()        ssid = url.split("/")[-2]        review.authors.append(Person(name=name, ssid=ssid, profile_url=url))    content = data.xpath("//div[@class='single__entry-content'] | //body[p | strong | ul | h2 | h3 | h4 | blockquote]").first()    pros = content.xpath(r"p[regexp:test(.//text(), '(?=.*what)((?=.*\swe\s)|(?=.*\si\s))((?=.*like)|(?=.*love)).*', 'i')]/following-sibling::ul[1]/li")    if not pros:        pros = data.xpath("//p[contains(., 'positive')]/following-sibling::ul[1]/li")    for pro in pros:        pro = pro.xpath(".//text()").string(multiple=True)        review.properties.append(ReviewProperty(type="pros", value=pro))    cons = content.xpath(r"p[regexp:test(.//text(), '(?=.*what)((?=.*\swe\s)|(?=.*\si\s))((?=.*did.?n.t.*like)|(?=.*hate)).*', 'i')]/following-sibling::ul[1]/li")    if not cons:        cons = content.xpath(".//p[contains(., 'negative')]/following-sibling::ul[1]/li")    for con in cons:        con = con.xpath(".//text()").string(multiple=True)        review.properties.append(ReviewProperty(type="cons", value=con))    summary = content.xpath("p[1]//text()").string(multiple=True)    if summary:        review.properties.append(ReviewProperty(type="summary", value=summary))    conclusion = content.xpath("h3[regexp:test(.//text(), 'conclusion|verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath("h4[regexp:test(.//text(), 'conclusion|verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath("strong[regexp:test(.//text(), 'conclusion|verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//h3[regexp:test(.//text(), '(?=.*final)(?=.*say)|(?=.*final)(?=.*thought).*', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//h4[regexp:test(.//text(), '(?=.*final)(?=.*say)|(?=.*final)(?=.*thought).*', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//strong[regexp:test(.//text(), '(?=.*final)(?=.*say)|(?=.*final)(?=.*thought).*', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//h3[regexp:test(.//text(), 'verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//h4[regexp:test(.//text(), 'verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//strong[regexp:test(.//text(), 'verdict', 'i')]/following-sibling::*[self::p | self::strong | self::ul | self::h2 | self::h3 | self::h4 | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//blockquote[p[regexp:test(.//text(), 'verdict', 'i')][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]]//text()").string(multiple=True)    if not conclusion:        conclusion = content.xpath(".//blockquote[last()]//text()").string(multiple=True)    if conclusion:        review.properties.append(ReviewProperty(type="conclusion", value=conclusion))    excerpt = content.xpath("*[self::p | self::strong | self::ul | self::blockquote][not(a and regexp:test(.//text(), 'read more.?:', 'i'))][not(regexp:test(.//text(), '(?=.*image)(?=.*" + review.authors[0].name + ")?(?=.*/.*burn)', 'i'))][not(regexp:test(.//text(), '.*Disclaimer.?:|score:', 'i'))]//text()").string(multiple=True)    if excerpt:        if summary:            excerpt = excerpt.replace(summary, '')        if conclusion:            excerpt = excerpt.split(conclusion.split('.')[0])[0]        excerpt = excerpt.strip()        review.properties.append(ReviewProperty(type="excerpt", value=excerpt))    grade = data.xpath("//blockquote/p[contains(., 'Score')]//text()").string(multiple=True)    if grade:        if "Score" in grade:            if "Score: " in grade:                grade = grade.split("Score: ")[1].split(" (")[0]            if "Score : " in grade:                grade = grade.split("Score : ")[1].split(" (")[0]            if " gets an entertaining " in grade:                grade = grade.split(" gets an entertaining ")[1]            if " out of " in grade:                grades = grade.split(" out of ")            elif "/" in grade:                grades = grade.split("/")            else:                grades = [grade, 10]            grades[0] = str(grades[0]).split(" ")[0]            grades[1] = str(grades[1]).split(" ")[0]            review.grades.append(Grade(value=grades[0], best=grades[1], worst=0, name="Grade", type="overall"))    if summary or excerpt or conclusion:        product.reviews.append(review)        session.emit(product)